import{_ as l,o as i,c as e,ag as r}from"./chunks/framework.-Wrcbzkw.js";const b=JSON.parse('{"title":"数据结构","description":"","frontmatter":{},"headers":[],"relativePath":"basic/数据结构与算法/数据结构.md","filePath":"basic/数据结构与算法/数据结构.md","lastUpdated":1778838314000}'),t={name:"basic/数据结构与算法/数据结构.md"};function h(o,a,n,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h1><h2 id="一、线性结构" tabindex="-1">一、线性结构 <a class="header-anchor" href="#一、线性结构" aria-label="Permalink to &quot;一、线性结构&quot;">​</a></h2><h3 id="数组-array" tabindex="-1">数组（Array） <a class="header-anchor" href="#数组-array" aria-label="Permalink to &quot;数组（Array）&quot;">​</a></h3><ul><li>连续内存存储</li><li>随机访问 O(1)</li><li>插入/删除 O(n)</li></ul><h3 id="链表-linked-list" tabindex="-1">链表（Linked List） <a class="header-anchor" href="#链表-linked-list" aria-label="Permalink to &quot;链表（Linked List）&quot;">​</a></h3><ul><li>节点通过指针连接</li><li>插入/删除 O(1)</li><li>访问 O(n)</li><li>单链表、双链表、循环链表</li></ul><h3 id="栈-stack" tabindex="-1">栈（Stack） <a class="header-anchor" href="#栈-stack" aria-label="Permalink to &quot;栈（Stack）&quot;">​</a></h3><ul><li>先进后出（LIFO）</li><li>操作：push（入栈）、pop（出栈）</li><li>应用：函数调用栈、括号匹配</li></ul><h3 id="队列-queue" tabindex="-1">队列（Queue） <a class="header-anchor" href="#队列-queue" aria-label="Permalink to &quot;队列（Queue）&quot;">​</a></h3><ul><li>先进先出（FIFO）</li><li>操作：enqueue（入队）、dequeue（出队）</li><li>优先队列、循环队列</li></ul><h2 id="二、散列结构" tabindex="-1">二、散列结构 <a class="header-anchor" href="#二、散列结构" aria-label="Permalink to &quot;二、散列结构&quot;">​</a></h2><h3 id="哈希表-hash-table" tabindex="-1">哈希表（Hash Table） <a class="header-anchor" href="#哈希表-hash-table" aria-label="Permalink to &quot;哈希表（Hash Table）&quot;">​</a></h3><ul><li>键值对存储</li><li>查找 O(1)</li><li>冲突解决：链地址法、开放地址法</li><li>JavaScript 中对象和 Map 就是哈希表</li></ul><h2 id="三、树形结构" tabindex="-1">三、树形结构 <a class="header-anchor" href="#三、树形结构" aria-label="Permalink to &quot;三、树形结构&quot;">​</a></h2><h3 id="二叉树" tabindex="-1">二叉树 <a class="header-anchor" href="#二叉树" aria-label="Permalink to &quot;二叉树&quot;">​</a></h3><ul><li>每个节点最多两个子节点</li><li>遍历方式： <ul><li>前序：根 → 左 → 右</li><li>中序：左 → 根 → 右</li><li>后序：左 → 右 → 根</li><li>层序：按层次遍历</li></ul></li></ul><h3 id="二叉搜索树-bst" tabindex="-1">二叉搜索树（BST） <a class="header-anchor" href="#二叉搜索树-bst" aria-label="Permalink to &quot;二叉搜索树（BST）&quot;">​</a></h3><ul><li>左子树所有节点小于根节点</li><li>右子树所有节点大于根节点</li><li>查找、插入、删除 O(log n)</li></ul><h3 id="平衡树" tabindex="-1">平衡树 <a class="header-anchor" href="#平衡树" aria-label="Permalink to &quot;平衡树&quot;">​</a></h3><ul><li>AVL 树、红黑树</li><li>自动平衡，保证操作 O(log n)</li></ul><h2 id="四、图结构" tabindex="-1">四、图结构 <a class="header-anchor" href="#四、图结构" aria-label="Permalink to &quot;四、图结构&quot;">​</a></h2><h3 id="图-graph" tabindex="-1">图（Graph） <a class="header-anchor" href="#图-graph" aria-label="Permalink to &quot;图（Graph）&quot;">​</a></h3><ul><li>顶点（Vertex）和边（Edge）</li><li>有向图 / 无向图</li><li>邻接矩阵、邻接表存储</li></ul><h3 id="常用算法" tabindex="-1">常用算法 <a class="header-anchor" href="#常用算法" aria-label="Permalink to &quot;常用算法&quot;">​</a></h3><ul><li>BFS（广度优先搜索）</li><li>DFS（深度优先搜索）</li><li>Dijkstra 最短路径</li></ul>',25)])])}const q=l(t,[["render",h]]);export{b as __pageData,q as default};
